import{_ as e,a}from"./chunks/填写github渠道配置.B-S0-llS.js";import{_ as s,o as d,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"GitHub Releases 渠道添加说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/upload/github-releases.md","filePath":"cn/upload/github-releases.md","lastUpdated":1781962217000}'),l={name:"cn/upload/github-releases.md"};function n(r,t,c,h,p,b){return d(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="github-releases-渠道添加说明" tabindex="-1">GitHub Releases 渠道添加说明 <a class="header-anchor" href="#github-releases-渠道添加说明" aria-label="Permalink to &quot;GitHub Releases 渠道添加说明&quot;">​</a></h1><h2 id="添加前要准备什么" tabindex="-1">添加前要准备什么 <a class="header-anchor" href="#添加前要准备什么" aria-label="Permalink to &quot;添加前要准备什么&quot;">​</a></h2><p>在开始之前，你只需要准备这 3 样：</p><table tabindex="0"><thead><tr><th>需要准备</th><th>用途</th></tr></thead><tbody><tr><td>GitHub 账号</td><td>用来生成 Access Token，并作为仓库所属账号</td></tr><tr><td>GitHub Access Token</td><td>系统通过它访问 GitHub API、创建 Release、上传文件</td></tr><tr><td>一个仓库名称</td><td>可以只填仓库名，例如 <code>image</code></td></tr></tbody></table><h2 id="添加步骤" tabindex="-1">添加步骤 <a class="header-anchor" href="#添加步骤" aria-label="Permalink to &quot;添加步骤&quot;">​</a></h2><h3 id="第一步-登录-github-并生成-access-token" tabindex="-1">第一步：登录 GitHub 并生成 Access Token <a class="header-anchor" href="#第一步-登录-github-并生成-access-token" aria-label="Permalink to &quot;第一步：登录 GitHub 并生成 Access Token&quot;">​</a></h3><p>操作顺序如下：</p><ol><li>登录 GitHub。</li><li>点击右上角头像，进入 <code>Settings</code>。</li><li>在左侧找到 <code>Developer settings</code>。</li><li>进入 <code>Personal access tokens</code>。</li><li>打开 <code>Tokens (classic)</code>。</li><li>点击 <code>Generate new token (classic)</code>。</li><li>给这枚令牌起一个名字，方便你自己识别。</li><li>过期时间按你的使用习惯选择。</li><li>在权限里勾选 <code>repo</code> 和 <code>workflow</code>。</li><li>创建后立即复制保存。</li></ol><p><img src="'+e+'" alt="添加github权限" loading="lazy"></p><h2 id="第二步-回到系统里填写-github-releases-渠道" tabindex="-1">第二步：回到系统里填写 GitHub Releases 渠道 <a class="header-anchor" href="#第二步-回到系统里填写-github-releases-渠道" aria-label="Permalink to &quot;第二步：回到系统里填写 GitHub Releases 渠道&quot;">​</a></h2><p>在上传设置里选择 <code>GitHub Releases</code> 后，按下面这套填：</p><table tabindex="0"><thead><tr><th>页面字段</th><th>你该填什么</th></tr></thead><tbody><tr><td>渠道名称</td><td>你自己起，比如 <code>GitHub主仓库</code></td></tr><tr><td>Access Token</td><td>刚才生成的 GitHub Personal Access Token</td></tr><tr><td>仓库名称</td><td>可以只填仓库名，例如 <code>image</code>；也可以直接填完整路径，例如 <code>用户名/image</code></td></tr><tr><td>私有仓库</td><td>按你的需求决定开或关</td></tr><tr><td>备注</td><td>可选，例如 <code>主上传渠道</code></td></tr></tbody></table><p><img src="'+a+`" alt="填写github渠道配置" loading="lazy"></p><h2 id="第三步-保存渠道配置" tabindex="-1">第三步：保存渠道配置 <a class="header-anchor" href="#第三步-保存渠道配置" aria-label="Permalink to &quot;第三步：保存渠道配置&quot;">​</a></h2><p>字段填好以后，直接点击保存。 这一步系统会做两件事：</p><table tabindex="0"><thead><tr><th>系统动作</th><th>说明</th></tr></thead><tbody><tr><td>只填仓库名时</td><td>系统会先识别当前 GitHub 账号，再自动拼成完整仓库地址</td></tr><tr><td>填完整路径时</td><td>系统直接按你填写的 <code>名字/仓库名</code> 执行，不再改写</td></tr><tr><td>检查仓库是否存在</td><td>如果你走的是当前个人账号这条主线，仓库不存在时会自动创建；如果你手动填写完整路径，则按该路径直接执行</td></tr><tr><td>同步公开 / 私有状态</td><td>会按你当前开关设置处理</td></tr></tbody></table><h2 id="渠道的操作流程总结" tabindex="-1">渠道的操作流程总结 <a class="header-anchor" href="#渠道的操作流程总结" aria-label="Permalink to &quot;渠道的操作流程总结&quot;">​</a></h2><p>GitHub Releases 这条线可以直接理解成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>登录 GitHub</span></span>
<span class="line"><span>-&gt; 生成 Access Token</span></span>
<span class="line"><span>-&gt; 回系统填 Token 和仓库名称</span></span>
<span class="line"><span>-&gt; 保存</span></span>
<span class="line"><span>-&gt; 只填仓库名时系统自动补当前用户名；填写 名字/仓库名 时按原样执行</span></span>
<span class="line"><span>-&gt; 上传测试图</span></span></code></pre></div>`,19)])])}const k=s(l,[["render",n]]);export{m as __pageData,k as default};
